/**
 * Threat/Aggro System
 * Manages enemy targeting based on threat generated by players
 */

// Threat modifiers for different actions
export const THREAT_MODIFIERS = {
  // Damage-based threat
  DAMAGE: { id: 'damage', name: 'Damage', baseMod: 1.0 },
  CRITICAL_HIT: { id: 'critical_hit', name: 'Critical Hit', baseMod: 1.5 },
  DOT_TICK: { id: 'dot_tick', name: 'DoT Tick', baseMod: 0.5 },

  // Healing-based threat
  HEAL_SELF: { id: 'heal_self', name: 'Self Heal', baseMod: 0.5 },
  HEAL_OTHER: { id: 'heal_other', name: 'Heal Other', baseMod: 1.0 },
  OVERHEAL: { id: 'overheal', name: 'Overheal', baseMod: 0.25 },

  // Action-based threat
  TAUNT: { id: 'taunt', name: 'Taunt', baseMod: 0 }, // Fixed amount
  ATTACK_MISS: { id: 'attack_miss', name: 'Attack Miss', baseMod: 0.1 },
  BUFF_ALLY: { id: 'buff_ally', name: 'Buff Ally', baseMod: 0.3 },
  DEBUFF_ENEMY: { id: 'debuff_enemy', name: 'Debuff Enemy', baseMod: 0.5 },

  // Special actions
  RESURRECT: { id: 'resurrect', name: 'Resurrect', baseMod: 3.0 },
  SUMMON: { id: 'summon', name: 'Summon', baseMod: 1.5 }
};

// Threat reduction modifiers
export const THREAT_REDUCTION = {
  FADE: { id: 'fade', name: 'Fade', reduction: 0.5 },
  FEIGN_DEATH: { id: 'feign_death', name: 'Feign Death', reduction: 1.0 },
  VANISH: { id: 'vanish', name: 'Vanish', reduction: 1.0 },
  THREAT_DUMP: { id: 'threat_dump', name: 'Threat Dump', reduction: 0.3 }
};

// Tank stance modifiers
export const TANK_STANCES = {
  DEFENSIVE: { id: 'defensive', name: 'Defensive Stance', threatMod: 1.5, damageMod: 0.9 },
  AGGRESSIVE: { id: 'aggressive', name: 'Aggressive Stance', threatMod: 1.2, damageMod: 1.0 },
  NORMAL: { id: 'normal', name: 'Normal Stance', threatMod: 1.0, damageMod: 1.0 }
};

// Aggro states
export const AGGRO_STATE = {
  IDLE: { id: 'idle', name: 'Idle', color: '#888888' },
  ENGAGED: { id: 'engaged', name: 'Engaged', color: '#FFAA00' },
  ATTACKING: { id: 'attacking', name: 'Attacking', color: '#FF0000' },
  RETURNING: { id: 'returning', name: 'Returning', color: '#00AAFF' }
};

/**
 * Initialize threat state
 */
export function initThreatState() {
  return {
    threatTables: {}, // enemyId -> { targetId: threatValue }
    aggroStates: {}, // enemyId -> aggroState
    currentTargets: {}, // enemyId -> targetId
    playerStances: {}, // playerId -> stanceId
    threatModifiers: {}, // targetId -> modifier
    threatHistory: [],
    tauntEffects: {}, // targetId -> { taunter, expiresAt }
    fixatedTargets: {} // enemyId -> { targetId, expiresAt }
  };
}

/**
 * Get threat state from game state
 */
export function getThreatState(state) {
  return state.threat || initThreatState();
}

/**
 * Initialize threat table for an enemy
 */
export function initEnemyThreatTable(state, enemyId) {
  const threatState = getThreatState(state);

  if (threatState.threatTables[enemyId]) {
    return { state, initialized: false, error: 'Threat table already exists' };
  }

  return {
    state: {
      ...state,
      threat: {
        ...threatState,
        threatTables: {
          ...threatState.threatTables,
          [enemyId]: {}
        },
        aggroStates: {
          ...threatState.aggroStates,
          [enemyId]: AGGRO_STATE.IDLE.id
        }
      }
    },
    initialized: true
  };
}

/**
 * Generate threat against an enemy
 */
export function generateThreat(state, targetId, enemyId, amount, options = {}) {
  const { modifierType = 'damage', isCritical = false, stance = null } = options;

  const threatState = getThreatState(state);
  const threatTable = threatState.threatTables[enemyId];

  if (!threatTable) {
    return { state, generated: false, error: 'Enemy has no threat table' };
  }

  // Calculate modifier
  let modifier = 1.0;

  // Apply action-type modifier
  const threatMod = THREAT_MODIFIERS[modifierType.toUpperCase()];
  if (threatMod) {
    modifier *= threatMod.baseMod;
  }

  // Apply critical hit bonus
  if (isCritical) {
    modifier *= THREAT_MODIFIERS.CRITICAL_HIT.baseMod;
  }

  // Apply stance modifier
  const playerStance = stance || threatState.playerStances[targetId] || 'normal';
  const stanceData = TANK_STANCES[playerStance.toUpperCase()];
  if (stanceData) {
    modifier *= stanceData.threatMod;
  }

  // Apply global target modifier
  const globalMod = threatState.threatModifiers[targetId] || 1.0;
  modifier *= globalMod;

  const finalThreat = Math.max(0, Math.floor(amount * modifier));
  const currentThreat = threatTable[targetId] || 0;
  const newThreat = currentThreat + finalThreat;

  // Create history entry
  const historyEntry = {
    timestamp: Date.now(),
    targetId,
    enemyId,
    baseAmount: amount,
    modifier,
    finalThreat,
    totalThreat: newThreat
  };

  // Update aggro state
  let newAggroState = threatState.aggroStates[enemyId];
  if (newAggroState === 'idle' && newThreat > 0) {
    newAggroState = 'engaged';
  }

  return {
    state: {
      ...state,
      threat: {
        ...threatState,
        threatTables: {
          ...threatState.threatTables,
          [enemyId]: {
            ...threatTable,
            [targetId]: newThreat
          }
        },
        aggroStates: {
          ...threatState.aggroStates,
          [enemyId]: newAggroState
        },
        threatHistory: [...threatState.threatHistory.slice(-99), historyEntry]
      }
    },
    generated: true,
    finalThreat,
    totalThreat: newThreat,
    modifier
  };
}

/**
 * Reduce threat against an enemy
 */
export function reduceThreat(state, targetId, enemyId, amount, options = {}) {
  const { reductionType = null, percentReduction = null } = options;

  const threatState = getThreatState(state);
  const threatTable = threatState.threatTables[enemyId];

  if (!threatTable) {
    return { state, reduced: false, error: 'Enemy has no threat table' };
  }

  const currentThreat = threatTable[targetId] || 0;
  let reduction = amount;

  // Apply reduction type
  if (reductionType) {
    const reductionData = THREAT_REDUCTION[reductionType.toUpperCase()];
    if (reductionData) {
      reduction = currentThreat * reductionData.reduction;
    }
  }

  // Apply percentage reduction
  if (percentReduction !== null) {
    reduction = currentThreat * percentReduction;
  }

  const newThreat = Math.max(0, currentThreat - reduction);

  return {
    state: {
      ...state,
      threat: {
        ...threatState,
        threatTables: {
          ...threatState.threatTables,
          [enemyId]: {
            ...threatTable,
            [targetId]: newThreat
          }
        }
      }
    },
    reduced: true,
    amountReduced: currentThreat - newThreat,
    newThreat
  };
}

/**
 * Apply taunt effect
 */
export function applyTaunt(state, taunter, targetId, enemyId, duration = 5000) {
  const threatState = getThreatState(state);
  const threatTable = threatState.threatTables[enemyId];

  if (!threatTable) {
    return { state, applied: false, error: 'Enemy has no threat table' };
  }

  // Get highest threat value and set taunter to that + bonus
  const maxThreat = Math.max(0, ...Object.values(threatTable));
  const tauntThreat = maxThreat + 100;

  return {
    state: {
      ...state,
      threat: {
        ...threatState,
        threatTables: {
          ...threatState.threatTables,
          [enemyId]: {
            ...threatTable,
            [taunter]: tauntThreat
          }
        },
        tauntEffects: {
          ...threatState.tauntEffects,
          [taunter]: {
            enemyId,
            expiresAt: Date.now() + duration
          }
        },
        fixatedTargets: {
          ...threatState.fixatedTargets,
          [enemyId]: {
            targetId: taunter,
            expiresAt: Date.now() + duration
          }
        }
      }
    },
    applied: true,
    newThreat: tauntThreat,
    duration
  };
}

/**
 * Get current threat target for an enemy
 */
export function getThreatTarget(state, enemyId) {
  const threatState = getThreatState(state);

  // Check for fixate effect
  const fixate = threatState.fixatedTargets[enemyId];
  if (fixate && Date.now() < fixate.expiresAt) {
    return { targetId: fixate.targetId, reason: 'fixate' };
  }

  // Get from threat table
  const threatTable = threatState.threatTables[enemyId];
  if (!threatTable || Object.keys(threatTable).length === 0) {
    return { targetId: null, reason: 'no_threat' };
  }

  // Find highest threat
  let highestThreat = -1;
  let highestTarget = null;

  for (const [targetId, threat] of Object.entries(threatTable)) {
    if (threat > highestThreat) {
      highestThreat = threat;
      highestTarget = targetId;
    }
  }

  return { targetId: highestTarget, threat: highestThreat, reason: 'threat' };
}

/**
 * Update enemy target based on threat
 */
export function updateEnemyTarget(state, enemyId) {
  const threatState = getThreatState(state);
  const { targetId, reason } = getThreatTarget(state, enemyId);

  const newAggroState = targetId ? 'attacking' : threatState.aggroStates[enemyId];

  return {
    state: {
      ...state,
      threat: {
        ...threatState,
        currentTargets: {
          ...threatState.currentTargets,
          [enemyId]: targetId
        },
        aggroStates: {
          ...threatState.aggroStates,
          [enemyId]: newAggroState
        }
      }
    },
    targetId,
    reason,
    previousTarget: threatState.currentTargets[enemyId]
  };
}

/**
 * Set player stance
 */
export function setPlayerStance(state, playerId, stanceId) {
  const stance = TANK_STANCES[stanceId.toUpperCase()];
  if (!stance) {
    return { state, set: false, error: 'Invalid stance' };
  }

  const threatState = getThreatState(state);

  return {
    state: {
      ...state,
      threat: {
        ...threatState,
        playerStances: {
          ...threatState.playerStances,
          [playerId]: stanceId
        }
      }
    },
    set: true,
    stance
  };
}

/**
 * Set global threat modifier for a target
 */
export function setThreatModifier(state, targetId, modifier) {
  const threatState = getThreatState(state);

  return {
    state: {
      ...state,
      threat: {
        ...threatState,
        threatModifiers: {
          ...threatState.threatModifiers,
          [targetId]: modifier
        }
      }
    },
    set: true
  };
}

/**
 * Get threat table for an enemy
 */
export function getThreatTable(state, enemyId) {
  const threatState = getThreatState(state);
  const threatTable = threatState.threatTables[enemyId] || {};

  // Sort by threat value
  return Object.entries(threatTable)
    .map(([targetId, threat]) => ({ targetId, threat }))
    .sort((a, b) => b.threat - a.threat);
}

/**
 * Get threat value for a specific target
 */
export function getTargetThreat(state, targetId, enemyId) {
  const threatState = getThreatState(state);
  const threatTable = threatState.threatTables[enemyId] || {};
  return threatTable[targetId] || 0;
}

/**
 * Clear threat for a target (e.g., on death)
 */
export function clearTargetThreat(state, targetId, enemyId = null) {
  const threatState = getThreatState(state);
  const newThreatTables = { ...threatState.threatTables };

  if (enemyId) {
    // Clear from specific enemy
    if (newThreatTables[enemyId]) {
      const newTable = { ...newThreatTables[enemyId] };
      delete newTable[targetId];
      newThreatTables[enemyId] = newTable;
    }
  } else {
    // Clear from all enemies
    for (const enemy of Object.keys(newThreatTables)) {
      const newTable = { ...newThreatTables[enemy] };
      delete newTable[targetId];
      newThreatTables[enemy] = newTable;
    }
  }

  return {
    state: {
      ...state,
      threat: {
        ...threatState,
        threatTables: newThreatTables
      }
    },
    cleared: true
  };
}

/**
 * Reset all threat for an enemy
 */
export function resetEnemyThreat(state, enemyId) {
  const threatState = getThreatState(state);

  return {
    state: {
      ...state,
      threat: {
        ...threatState,
        threatTables: {
          ...threatState.threatTables,
          [enemyId]: {}
        },
        currentTargets: {
          ...threatState.currentTargets,
          [enemyId]: null
        },
        aggroStates: {
          ...threatState.aggroStates,
          [enemyId]: 'idle'
        }
      }
    },
    reset: true
  };
}

/**
 * Clean up expired effects
 */
export function cleanupExpiredEffects(state) {
  const threatState = getThreatState(state);
  const now = Date.now();
  let cleaned = 0;

  const newTauntEffects = {};
  for (const [id, effect] of Object.entries(threatState.tauntEffects)) {
    if (effect.expiresAt > now) {
      newTauntEffects[id] = effect;
    } else {
      cleaned++;
    }
  }

  const newFixatedTargets = {};
  for (const [id, fixate] of Object.entries(threatState.fixatedTargets)) {
    if (fixate.expiresAt > now) {
      newFixatedTargets[id] = fixate;
    } else {
      cleaned++;
    }
  }

  return {
    state: {
      ...state,
      threat: {
        ...threatState,
        tauntEffects: newTauntEffects,
        fixatedTargets: newFixatedTargets
      }
    },
    cleaned
  };
}

/**
 * Get aggro state for an enemy
 */
export function getAggroState(state, enemyId) {
  const threatState = getThreatState(state);
  const stateId = threatState.aggroStates[enemyId] || 'idle';
  return AGGRO_STATE[stateId.toUpperCase()] || AGGRO_STATE.IDLE;
}

/**
 * Set aggro state for an enemy
 */
export function setAggroState(state, enemyId, aggroStateId) {
  const aggroState = AGGRO_STATE[aggroStateId.toUpperCase()];
  if (!aggroState) {
    return { state, set: false, error: 'Invalid aggro state' };
  }

  const threatState = getThreatState(state);

  return {
    state: {
      ...state,
      threat: {
        ...threatState,
        aggroStates: {
          ...threatState.aggroStates,
          [enemyId]: aggroStateId
        }
      }
    },
    set: true,
    aggroState
  };
}

/**
 * Get threat statistics
 */
export function getThreatStats(state) {
  const threatState = getThreatState(state);

  const enemyCount = Object.keys(threatState.threatTables).length;
  const activeEnemies = Object.entries(threatState.aggroStates)
    .filter(([_, s]) => s !== 'idle').length;

  const totalThreats = {};
  for (const table of Object.values(threatState.threatTables)) {
    for (const [targetId, threat] of Object.entries(table)) {
      totalThreats[targetId] = (totalThreats[targetId] || 0) + threat;
    }
  }

  const topThreats = Object.entries(totalThreats)
    .map(([targetId, threat]) => ({ targetId, threat }))
    .sort((a, b) => b.threat - a.threat)
    .slice(0, 5);

  return {
    enemyCount,
    activeEnemies,
    totalThreats,
    topThreats,
    recentHistory: threatState.threatHistory.slice(-10)
  };
}

/**
 * Calculate threat from damage
 */
export function threatFromDamage(damage, options = {}) {
  const { isCritical = false, isDoT = false, stanceMod = 1.0 } = options;

  let threat = damage;

  if (isCritical) {
    threat *= THREAT_MODIFIERS.CRITICAL_HIT.baseMod;
  }

  if (isDoT) {
    threat *= THREAT_MODIFIERS.DOT_TICK.baseMod;
  }

  threat *= stanceMod;

  return Math.floor(threat);
}

/**
 * Calculate threat from healing
 */
export function threatFromHealing(healing, options = {}) {
  const { isSelfHeal = false, overhealAmount = 0 } = options;

  let threat = healing - overhealAmount;

  if (isSelfHeal) {
    threat *= THREAT_MODIFIERS.HEAL_SELF.baseMod;
  } else {
    threat *= THREAT_MODIFIERS.HEAL_OTHER.baseMod;
  }

  // Add reduced threat for overheal
  threat += overhealAmount * THREAT_MODIFIERS.OVERHEAL.baseMod;

  return Math.floor(threat);
}

/**
 * Check if target has aggro from enemy
 */
export function hasAggro(state, targetId, enemyId) {
  const { targetId: currentTarget } = getThreatTarget(state, enemyId);
  return currentTarget === targetId;
}

/**
 * Get all enemies targeting a specific player
 */
export function getEnemiesTargeting(state, targetId) {
  const threatState = getThreatState(state);
  const enemies = [];

  for (const [enemyId, currentTarget] of Object.entries(threatState.currentTargets)) {
    if (currentTarget === targetId) {
      enemies.push(enemyId);
    }
  }

  return enemies;
}

/**
 * Remove enemy from threat system
 */
export function removeEnemy(state, enemyId) {
  const threatState = getThreatState(state);

  const newThreatTables = { ...threatState.threatTables };
  delete newThreatTables[enemyId];

  const newAggroStates = { ...threatState.aggroStates };
  delete newAggroStates[enemyId];

  const newCurrentTargets = { ...threatState.currentTargets };
  delete newCurrentTargets[enemyId];

  const newFixatedTargets = { ...threatState.fixatedTargets };
  delete newFixatedTargets[enemyId];

  return {
    state: {
      ...state,
      threat: {
        ...threatState,
        threatTables: newThreatTables,
        aggroStates: newAggroStates,
        currentTargets: newCurrentTargets,
        fixatedTargets: newFixatedTargets
      }
    },
    removed: true
  };
}
